Bash(node -e "
const puppeteer = require\(''puppeteer''\);

\(async \(\) => {
  const browser = await puppeteer.launch\({
    headless: ''new'',
    executablePath: ''/Applications/Google Chrome.app/Contents/MacOS/Google Chrome'',
    args: [''--no-sandbox'']
  }\);
  const page = await browser.newPage\(\);
  await page.goto\(''https://www.hannovermesse.de/de/applikation/formulare/kontakt-aussteller/?exhibitor=aashirwad-press-tools&directLink=N1611362'', { waitUntil: ''domcontentloaded'', timeout: 60000 }\);
  await page.waitForSelector\(''form'', { timeout: 15000 }\);
  await new Promise\(r => setTimeout\(r, 2000\)\);
  await page.mouse.click\(590, 383\);
  await new Promise\(r => setTimeout\(r, 1000\)\);

  // Find country/nation related elements
  const countryElements = await page.evaluate\(\(\) => {
    const elements = document.querySelectorAll\(''[name*=""nation""], [name*=""country""], [id*=""nation""], [id*=""country""], select, [class*=""country""], [class*=""nation""]''\);
    return Array.from\(elements\).map\(el => \({
      tag: el.tagName,
      type: el.type,
      id: el.id,
      name: el.name,
      className: el.className,
      options: el.tagName === ''SELECT'' ? Array.from\(el.options\).slice\(0,5\).map\(o => \({value: o.value, text: o.text}\)\) : null
    }\)\);
  }\);

  console.log\(JSON.stringify\(countryElements, null, 2\)\);
  await browser.close\(\);
}\)\(\);
")
